;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@barrel noguest
@damage v=&'game.curTarget.addParam("magic", 9)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had MP restored!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("vitality", 2)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Vitality permanently increased by 2!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

; ハイパーボム専用宝箱
